type SlackOverride func(cred string, args map[string]any) (any, error)

// Slack is an in-process, bring-your-own-key client.
type Slack struct {
	cred      string
	http      *http.Client
	overrides map[string]SlackOverride
}

type SlackOption func(*Slack)

func SlackWithHTTPClient(c *http.Client) SlackOption { return func(s *Slack) { s.http = c } }

func SlackWithOverride(action string, fn SlackOverride) SlackOption {
	return func(s *Slack) { s.overrides[action] = fn }
}

// NewSlack constructs a client for the given API key.
func NewSlack(credential string, opts ...SlackOption) *Slack {
	s := &Slack{cred: credential, http: http.DefaultClient, overrides: map[string]SlackOverride{}}
	for _, o := range opts {
		o(s)
	}
	return s
}

func (s *Slack) execute(action string, args map[string]any) (any, error) {
	return ExecuteWith(s.http, SLACK, action, args, s.cred)
}

func (s *Slack) paginate(action string, args map[string]any) ([]any, error) {
	return PaginateWith(s.http, SLACK, action, args, s.cred)
}

